```java
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class XPathToSelector {

    public static void main(String[] args) {
        String xpath = "//input[@type='text']";
        String selector = convertXPathToSelector(xpath);
        System.out.println(selector);
    }

    public static String convertXPathToSelector(String xpath) {
        String regex = "([a-zA-Z]\\w*)(\\s+[a-zA-Z0-9-_:.]+)*";
        String pattern = "\\s*(\\w+)\\s*=\\s*(\\w+)\\s*";
        String[] parts = xpath.split("/");
        StringBuilder selector = new StringBuilder();
        for (int i = 0; i < parts.length; i++) {
            String part = parts[i];
            if (part.contains("@")) {
                String attribute = part.split("\\@")[0];
                String value = part.split("\\@")[1];
                selector.append(attribute).append("=").append(value);
            } else {
                Matcher matcher = Pattern.compile(regex).matcher(part);
                while (matcher.find()) {
                    String key = matcher.group(1);
                    String value = matcher.group(2);
                    selector.append(key).append("=").append(value);
                }
            }
            if (i < parts.length - 1) {
                selector.append("\\s*");
            }
        }
        return selector.toString();
    }
}
```
